/* Dashboard.css */
.stat-card {
    border-radius: 16px !important;
    border: 1px solid #e2e8f0;
    box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05) !important;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.stat-card:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 15px -3px rgba(0, 0, 0, 0.1) !important;
}

.trend-badge {
    padding: 4px 8px;
    border-radius: 100px;
    font-size: 0.75rem;
    font-weight: 600;
    display: inline-flex;
    align-items: center;
    gap: 4px;
}

.trend-up-success {
    background-color: #dcfce7;
    color: #166534;
}

.trend-up-warning {
    background-color: #fef9c3;
    color: #854d0e;
}

.trend-down-neutral {
    background-color: #f1f5f9;
    color: #475569;
}

.dashboard-table-container {
    border-radius: 16px !important;
    border: 1px solid #e2e8f0;
    overflow: hidden;
}

.status-badge {
    padding: 4px 12px;
    border-radius: 100px;
    font-size: 0.75rem;
    font-weight: 600;
    display: inline-block;
}

.status-passed {
    background-color: #dcfce7;
    color: #166534;
}

.status-failed {
    background-color: #fee2e2;
    color: #991b1b;
}

.status-running {
    background-color: #e0f2fe;
    color: #0369a1;
}

.code-badge {
    font-family: 'Fira Code', monospace;
    background: #f1f5f9;
    padding: 2px 6px;
    border-radius: 4px;
    font-size: 0.85rem;
    color: #475569;
}
